import { Info, Plus, Trash2, X } from 'lucide-react-native';
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { ActivityIndicator, Alert, Animated, Dimensions, Image, Modal, ScrollView, StyleSheet, Text, TextInput, TouchableOpacity, View } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import YoutubePlayer from 'react-native-youtube-iframe';
import { supabase } from '../lib/supabase';
import ExerciseSelector from './exercise-selector';

const { width } = Dimensions.get('window');

export default function WorkoutsScreen() {
  const [exercises, setExercises] = useState<any[]>([]);
  const [savedExercises, setSavedExercises] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [showSelector, setShowSelector] = useState(false);
  const [selectedExercise, setSelectedExercise] = useState<any>(null);
  const [playing, setPlaying] = useState(false);

  // Valor animado para la barra de progreso
  const animatedProgress = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    fetchTodayWorkouts();
  }, []);

  // Lógica de animación
  useEffect(() => {
    const percentage = exercises.length > 0 ? (savedExercises.length / exercises.length) * 100 : 0;

    Animated.timing(animatedProgress, {
      toValue: percentage,
      duration: 600, 
      useNativeDriver: false,
    }).start();
  }, [savedExercises, exercises]);

  const onStateChange = useCallback((state: string) => {
    if (state === "ended") {
      setPlaying(false);
    }
  }, []);

  const fetchTodayWorkouts = async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;
      const today = new Date().toISOString().split('T')[0];

      const { data: logsData, error: logsError } = await supabase
        .from('workout_logs')
        .select(`*, exercises (*)`)
        .eq('user_id', user.id)
        .gte('logged_at', `${today}T00:00:00Z`)
        .lte('logged_at', `${today}T23:59:59Z`);

      if (logsError) throw logsError;

      if (logsData) {
        const savedIds: string[] = [];
        const loadedExercises: any[] = []; 

        logsData.forEach((log: any) => {
          if (!savedIds.includes(log.exercise_id)) {
            savedIds.push(log.exercise_id);
            const exerciseInfo = Array.isArray(log.exercises) ? log.exercises[0] : log.exercises;

            loadedExercises.push({ 
              ...exerciseInfo, 
              weight: log.weight_kg?.toString() || "", 
              sets: log.sets?.toString() || "", 
              reps: log.reps?.toString() || "" 
            });
          }
        });

        setExercises(loadedExercises);
        setSavedExercises(savedIds);
      }
    } catch (error) { 
      console.error("Error cargando entrenamientos:", error); 
    } finally { 
      setLoading(false); 
    }
  };

  const removeExercise = async (id: string) => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      const today = new Date().toISOString().split('T')[0];

      setExercises(exercises.filter(ex => ex.id !== id));
      setSavedExercises(savedExercises.filter(exId => exId !== id));

      if (user) { 
        await supabase
          .from('workout_logs')
          .delete()
          .eq('user_id', user.id)
          .eq('exercise_id', id)
          .gte('logged_at', `${today}T00:00:00Z`); 
      }
    } catch (error) {
      console.error("Error al borrar:", error);
    }
  };

  const addExerciseFromCatalogue = (newEx: any) => {
    const alreadyExists = exercises.find(e => e.id === newEx.id);

    if (alreadyExists) {
      Alert.alert(
        "Ejercicio ya añadido",
        `El ejercicio "${newEx.name}" ya está en tu lista de entrenamiento de hoy.`,
        [{ text: "Entendido", style: "cancel" }]
      );
    } else {
      setExercises([...exercises, { ...newEx, weight: '', sets: '', reps: '' }]);
    }
  };

  const handleInputChange = (id: string, field: string, value: string) => {
    setExercises(exercises.map(ex => ex.id === id ? { ...ex, [field]: value } : ex));
  };

  const handleSave = async (id: string) => {
    const exerciseData = exercises.find(ex => ex.id === id);
    if (!exerciseData) return;

    try {
      const { data: { user }, error: userError } = await supabase.auth.getUser();
      if (userError || !user) {
        alert("Sesión expirada. Por favor, vuelve a entrar.");
        return;
      }

      const today = new Date().toISOString().split('T')[0];

      if (savedExercises.includes(id)) {
        const { error } = await supabase
          .from('workout_logs')
          .delete()
          .eq('user_id', user.id)
          .eq('exercise_id', id)
          .gte('logged_at', `${today}T00:00:00Z`)
          .lte('logged_at', `${today}T23:59:59Z`);

        if (error) throw error;

        setSavedExercises(savedExercises.filter(exId => exId !== id));
      } else {
        const weight = parseFloat(exerciseData.weight) || 0;
        const sets = parseInt(exerciseData.sets) || 0;
        const reps = parseInt(exerciseData.reps) || 0;

        const { error } = await supabase
          .from('workout_logs')
          .insert([{
            exercise_id: id,
            user_id: user.id,
            weight_kg: weight,
            sets: sets,
            reps: reps,
            logged_at: new Date().toISOString()
          }]);

        if (error) throw error;

        setSavedExercises(prev => [...prev, id]);
      }
    } catch (err: any) {
      console.error("Error inesperado en handleSave:", err);
      alert(`Error al guardar: ${err.message || 'Error desconocido'}`);
    }
  };

  if (loading) {
    return (
      <View style={{ flex: 1, backgroundColor: '#09090b', justifyContent: 'center', alignItems: 'center' }}>
        <ActivityIndicator size="large" color="#E31C25" />
      </View>
    );
  }

  return (
    <SafeAreaView style={styles.safeArea} edges={['top', 'left', 'right']}>

      <Modal visible={showSelector} animationType="slide" presentationStyle="pageSheet">
        <ExerciseSelector onClose={() => setShowSelector(false)} onSelect={addExerciseFromCatalogue} />
      </Modal>

      <Modal visible={!!selectedExercise} animationType="fade" transparent={true}>
        <View style={styles.modalOverlay}>
          <View style={styles.videoModalContent}>
            <TouchableOpacity style={styles.closeModalButton} onPress={() => setSelectedExercise(null)}>
              <X color="#fff" size={24} />
            </TouchableOpacity>

            <View style={styles.videoPlayerContainer}>
              {selectedExercise?.video_url ? (
                <YoutubePlayer
                  height={250}
                  play={true}
                  videoId={selectedExercise.video_url}
                  onChangeState={onStateChange}
                  webViewProps={{ allowsFullscreenVideo: true }}
                />
              ) : (
                <View style={[styles.videoPlayerContainer, { justifyContent: 'center', alignItems: 'center', backgroundColor: '#27272a' }]}>
                  <Text style={{ color: '#a1a1aa' }}>Video no disponible</Text>
                </View>
              )}
            </View>

            <View style={styles.videoInfoContainer}>
              <Text style={styles.modalExerciseName}>{selectedExercise?.name}</Text>
              <Text style={styles.modalCategory}>{selectedExercise?.category}</Text>
              <Text style={styles.modalDescription}>
                {selectedExercise?.description || "Sin descripción disponible."}
              </Text>
            </View>
          </View>
        </View>
      </Modal>

      {/* --- CABECERA --- */}
      <View style={styles.header}>
        <View style={styles.headerTopRow}>
          <View>
            <Text style={styles.title}>Entrenamiento</Text>
            <Text style={styles.subtitle}>Tu sesión de hoy</Text>
          </View>

          <TouchableOpacity style={styles.smallAddButton} onPress={() => setShowSelector(true)} activeOpacity={0.8}>
            <Plus color="#fff" size={22} />
          </TouchableOpacity>
        </View>

        <View style={styles.progressSection}>
          <View style={styles.progressRow}>
            <Text style={styles.progressLabel}>Progreso de hoy</Text>
            <Text style={styles.progressValue}>
              {savedExercises.length}/{exercises.length} completados
            </Text>
          </View>
          <View style={styles.progressBarBg}>
            <Animated.View 
              style={[
                styles.progressBarFill, 
                { 
                  width: animatedProgress.interpolate({
                    inputRange: [0, 100],
                    outputRange: ['0%', '100%']
                  }) 
                } 
              ]} 
            />
          </View>
        </View>
      </View>

      {/* --- LISTA DE EJERCICIOS --- */}
      <ScrollView style={{ flex: 1 }} contentContainerStyle={styles.scrollContent}>
        <View style={styles.exerciseList}>
          {exercises.map((exercise) => {
            const isSaved = savedExercises.includes(exercise.id);
            return (
              <View key={exercise.id} style={styles.exerciseCard}>

                {/* CABECERA DE LA TARJETA MEJORADA CON ETIQUETA DE CATEGORÍA */}
                <View style={styles.cardHeaderRow}>
                   <View style={{ flex: 1, alignItems: 'flex-start' }}>
                     <TouchableOpacity 
                      style={{ flexDirection: 'row', alignItems: 'center', marginBottom: 6 }}
                      onPress={() => setSelectedExercise(exercise)}
                     >
                       <Text style={styles.exerciseName}>{exercise.name}</Text>
                       <Info color="#E31C25" size={16} style={{ marginLeft: 8 }} />
                     </TouchableOpacity>

                     {/* NUEVA ETIQUETA VISUAL */}
                     <View style={styles.categoryBadge}>
                       <Text style={styles.categoryBadgeText}>{exercise.category}</Text>
                     </View>
                   </View>

                   <TouchableOpacity onPress={() => removeExercise(exercise.id)} style={{ padding: 4 }}>
                     <Trash2 color="#ef4444" size={18} />
                   </TouchableOpacity>
                </View>

                <View style={styles.cardLayout}>
                  <TouchableOpacity onPress={() => setSelectedExercise(exercise)}>
                    <Image source={{ uri: exercise.thumbnail_url }} style={styles.thumbnail} />
                  </TouchableOpacity>
                  <View style={styles.detailsContainer}>
                    <View style={styles.inputGrid}>
                      <View style={styles.inputBox}>
                        <Text style={styles.inputLabel}>Kg</Text>
                        <TextInput
                          style={[styles.textInput, isSaved && styles.textInputDisabled]}
                          keyboardType="numeric"
                          value={exercise.weight?.toString() || ""}
                          onChangeText={(val) => handleInputChange(exercise.id, 'weight', val)}
                          editable={!isSaved}
                        />
                      </View>
                      <View style={styles.inputBox}>
                        <Text style={styles.inputLabel}>Sets</Text>
                        <TextInput
                          style={[styles.textInput, isSaved && styles.textInputDisabled]}
                          keyboardType="numeric"
                          value={exercise.sets?.toString() || ""}
                          onChangeText={(val) => handleInputChange(exercise.id, 'sets', val)}
                          editable={!isSaved}
                        />
                      </View>
                      <View style={styles.inputBox}>
                        <Text style={styles.inputLabel}>Reps</Text>
                        <TextInput
                          style={[styles.textInput, isSaved && styles.textInputDisabled]}
                          keyboardType="numeric"
                          value={exercise.reps?.toString() || ""}
                          onChangeText={(val) => handleInputChange(exercise.id, 'reps', val)}
                          editable={!isSaved}
                        />
                      </View>
                    </View>
                    <TouchableOpacity
                      onPress={() => handleSave(exercise.id)}
                      style={[styles.saveButton, isSaved ? styles.saveButtonActive : styles.saveButtonInactive]}
                    >
                      <Text style={[styles.saveButtonText, { color: isSaved ? '#fff' : '#a1a1aa' }]}>
                        {isSaved ? "¡Hecho!" : "Registrar ejercicio"}
                      </Text>
                    </TouchableOpacity>
                  </View>
                </View>
              </View>
            );
          })}
        </View>
      </ScrollView>

    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safeArea: { flex: 1, backgroundColor: '#09090b' },
  scrollContent: { paddingBottom: 40 },

