  smallAddButton: { width: 44, height: 44, borderRadius: 22, backgroundColor: '#E31C25', alignItems: 'center', justifyContent: 'center', shadowColor: '#E31C25', shadowOffset: { width: 0, height: 2 }, shadowOpacity: 0.4, shadowRadius: 6, elevation: 4 },

