  progressBarFill: { height: 16, backgroundColor: '#E31C25', borderRadius: 10, shadowColor: '#E31C25', shadowOffset: { width: 0, height: 0 }, shadowOpacity: 0.8, shadowRadius: 10, elevation: 8 },

  exerciseList: { padding: 20, gap: 16, paddingTop: 16 },
  exerciseCard: { backgroundColor: '#18181b', borderRadius: 20, padding: 16, borderWidth: 1, borderColor: '#27272a' },

  // Modificación del header de la tarjeta para acomodar la categoría
  cardHeaderRow: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 15 },
  exerciseName: { fontSize: 17, fontWeight: 'bold', color: '#fff' },

  // NUEVOS ESTILOS PARA LA ETIQUETA DE CATEGORÍA
  categoryBadge: {
    backgroundColor: 'rgba(227, 28, 37, 0.1)',
    paddingHorizontal: 8,
    paddingVertical: 4,
    borderRadius: 6,
    borderWidth: 1,
    borderColor: '#E31C25',
    alignSelf: 'flex-start'
  },
  categoryBadgeText: {
    color: '#E31C25',
    fontSize: 10,
    fontWeight: 'bold',
    textTransform: 'uppercase',
    letterSpacing: 0.5
  },

  cardLayout: { flexDirection: 'row', gap: 12 },
  thumbnail: { width: 70, height: 70, borderRadius: 12 },
  detailsContainer: { flex: 1 },
