  textInput: { backgroundColor: '#27272a', borderRadius: 8, padding: 8, color: '#fff', textAlign: 'center' },
  textInputDisabled: { backgroundColor: '#18181b', color: '#52525b', borderWidth: 1, borderColor: '#27272a' },
  saveButton: { paddingVertical: 10, borderRadius: 10, alignItems: 'center' },
