  videoModalContent: { width: width * 0.9, backgroundColor: '#18181b', borderRadius: 24, overflow: 'hidden', borderWidth: 1, borderColor: '#27272a' },
  closeModalButton: { position: 'absolute', top: 16, right: 16, zIndex: 10, backgroundColor: 'rgba(0,0,0,0.5)', borderRadius: 20, padding: 4 },
